import type { Language } from "@/i18n/translations";

export interface CategoryConfig {
  slug: string;
  label: string;
  emoji: string;
  title: string;
  h1: string;
  description: string;
  keywords: string;
  content: string;
  faq: { q: string; a: string }[];
  matchTags: string[];
  matchGender?: string[];
  matchMobile?: boolean;
}

type CatLang = Record<Language, Omit<CategoryConfig, "slug"|"emoji"|"matchTags"|"matchGender"|"matchMobile">>;

function cat(slug: string, emoji: string, matchTags: string[], langs: CatLang, extra?: { matchGender?: string[]; matchMobile?: boolean }): Record<Language, CategoryConfig> {
  const result: Record<string, CategoryConfig> = {};
  for (const lang of ["nl","en","fr","de","es","it"] as Language[]) {
    result[lang] = { slug, emoji, matchTags, ...langs[lang], ...(extra || {}) };
  }
  return result as Record<Language, CategoryConfig>;
}

